import { useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);

  const [search, setSearch] = useState("");

  const [searched, setSearched] = useState(false);

  const [date, setDate] = useState("");

  const [time1, setTime1] = useState("");

  const [time2, setTime2] = useState("");

  const [time3, setTime3] = useState("");

  const [sentRequests, setSentRequests] =
    useState({});


  // SEARCH WORKERS

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed to fetch workers");
    }
  };


  // SEND REQUEST

  const sendRequest = async (worker) => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {

          customerName: user.name,

          labourId: worker._id,

          labourName: worker.name,

          workType: search,

          date: date,

          timings: [
            time1,
            time2,
            time3
          ],

          status: "Pending"
        }
      );

      setSentRequests({
        ...sentRequests,
        [worker._id]: "Pending"
      });

      alert("Request Sent");

    } catch (err) {

      alert("Failed");
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* HEADER */}

        <div style={styles.header}>

          <h1 style={styles.heading}>
            Find Workers
          </h1>

          <p style={styles.subtext}>
            Search workers and send work requests
          </p>

        </div>

        {/* SEARCH */}

        <div style={styles.searchCard}>

          <input
            style={styles.input}
            placeholder="Search worker type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <input
            type="date"
            style={styles.input}
            value={date}
            onChange={(e) =>
              setDate(e.target.value)
            }
          />

          <select
            style={styles.input}
            onChange={(e) =>
              setTime1(e.target.value)
            }
          >
            <option>Time Slot 1</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime2(e.target.value)
            }
          >
            <option>Time Slot 2</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime3(e.target.value)
            }
          >
            <option>Time Slot 3</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* EMPTY */}

        {searched && workers.length === 0 && (

          <div style={styles.empty}>
            No workers found
          </div>

        )}

        {/* WORKERS */}

        <div style={styles.grid}>

          {workers.map(worker => (

            <div
              key={worker._id}
              style={styles.card}
            >

              <div style={styles.topSection}>

                <div style={styles.avatar}>
                  {worker.name?.charAt(0)}
                </div>

                <div>

                  <h2 style={styles.name}>
                    {worker.name}
                  </h2>

                  <p style={styles.skills}>
                    {worker.skills?.join(", ")}
                  </p>

                </div>

              </div>

              <div style={styles.infoBox}>

                <p style={styles.info}>
                  📍 {worker.city}, {worker.area}
                </p>

                <p style={styles.info}>
                  📞 {worker.phone}
                </p>

                <p style={styles.price}>
                  ₹ {worker.price}
                </p>

              </div>

              {/* STATUS */}

              {sentRequests[worker._id] && (

                <div style={styles.statusBox}>

                  <span style={styles.pending}>
                    {sentRequests[worker._id]}
                  </span>

                </div>

              )}

              {/* BUTTON */}

              <button
                style={styles.requestBtn}
                onClick={() =>
                  sendRequest(worker)
                }
              >
                Send Request
              </button>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 60px"
  },

  header: {
    marginBottom: "30px"
  },

  heading: {
    fontSize: "30px",
    color: "#111827",
    marginBottom: "8px"
  },

  subtext: {
    color: "#6b7280"
  },

  searchCard: {
    background: "white",
    padding: "24px",
    borderRadius: "16px",
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(180px,1fr))",
    gap: "15px",
    marginBottom: "35px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  input: {
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    fontSize: "14px",
    outline: "none"
  },

  searchBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "500"
  },

  empty: {
    background: "white",
    padding: "30px",
    borderRadius: "14px",
    textAlign: "center",
    color: "#6b7280"
  },

  grid: {
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(300px,1fr))",
    gap: "22px"
  },

  card: {
    background: "white",
    borderRadius: "18px",
    padding: "24px",
    boxShadow:
      "0 4px 15px rgba(0,0,0,0.05)"
  },

  topSection: {
    display: "flex",
    alignItems: "center",
    gap: "15px",
    marginBottom: "20px"
  },

  avatar: {
    width: "50px",
    height: "50px",
    borderRadius: "50%",
    background: "#2563eb",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontWeight: "bold",
    fontSize: "20px"
  },

  name: {
    margin: 0,
    fontSize: "20px"
  },

  skills: {
    color: "#6b7280",
    marginTop: "5px",
    fontSize: "14px"
  },

  infoBox: {
    marginBottom: "15px"
  },

  info: {
    marginBottom: "10px",
    color: "#374151",
    fontSize: "14px"
  },

  price: {
    fontWeight: "bold",
    color: "#2563eb",
    fontSize: "18px"
  },

  statusBox: {
    marginBottom: "18px"
  },

  pending: {
    background: "#fef3c7",
    color: "#b45309",
    padding: "7px 14px",
    borderRadius: "20px",
    fontSize: "13px",
    fontWeight: "500"
  },

  requestBtn: {
    width: "100%",
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "13px",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "500"
  }

};
